import sys

class Solution:
    def bstFromPreorder(self, preorder: list[int]) -> list[int]:
        if not preorder:
            return []
        root = preorder[0]
        greater = [x for x in preorder[1:] if x > root]
        lesser = [x for x in preorder[1:] if x <= root]
        return self.bstFromPreorder(lesser) + [root] + self.bstFromPreorder(greater)

if __name__ == '__main__':
    try:
        n = int(sys.stdin.readline().strip())
        preorder = [int(sys.stdin.readline().strip()) for _ in range(n)]
    except Exception as e:
        sys.exit(0)
    sol = Solution()
    ans = sol.bstFromPreorder(preorder)
    print(' '.join(map(str, ans)))

