#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> bstFromPreorder(vector<int>& preorder) {
        if (preorder.empty()) {
            return {};
        }
        int root = preorder[0];
        vector<int> greater;
        vector<int> lesser;
        for (int i = 1; i < preorder.size(); i++) {
            if (preorder[i] > root) {
                greater.push_back(preorder[i]);
            } else {
                lesser.push_back(preorder[i]);
            }
        }
        Solution sol;
        vector<int> left = sol.bstFromPreorder(lesser);
        vector<int> right = sol.bstFromPreorder(greater);
        left.push_back(root);
        left.insert(left.end(), right.begin(), right.end());
        return left;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<int> preorder(n);
    for (int i = 0; i < n; i++) {
        cin >> preorder[i];
    }
    Solution sol;
    vector<int> ans = sol.bstFromPreorder(preorder);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
